import os
import json
from typing import Any, Dict, Optional

class ConfigurationManager:
    def __init__(self, json_file_path: Optional[str] = None, defaults: Optional[Dict[str, Any]] = None):
        self._config = {}
        self._load_defaults(defaults)
        self._load_json_file(json_file_path)
        self._load_environment_variables()

    def _load_defaults(self, defaults: Optional[Dict[str, Any]]):
        if defaults:
            self._config.update(defaults)

    def _load_json_file(self, json_file_path: Optional[str]):
        if json_file_path and os.path.exists(json_file_path):
            with open(json_file_path, 'r') as json_file:
                try:
                    json_config = json.load(json_file)
                    self._config.update(json_config)
                except json.JSONDecodeError as e:
                    raise ValueError(f"Error decoding JSON from {json_file_path}: {e}")

    def _load_environment_variables(self):
        for key in self._config.keys():
            env_value = os.getenv(key)
            if env_value is not None:
                self._config[key] = env_value

    def get(self, key: str, default: Any = None) -> Any:
        return self._config.get(key, default)

    def set(self, key: str, value: Any):
        self._config[key] = value

    def all(self) -> Dict[str, Any]:
        return self._config.copy()

