import os
import json
from pathlib import Path

class ConfigurationManager:
    def __init__(self, default_config=None, json_file_path=None):
        self.default_config = default_config or {}
        self.json_config = self._load_json_config(json_file_path) if json_file_path else {}
        self.env_config = self._load_env_config()

    def _load_json_config(self, json_file_path):
        try:
            with open(json_file_path, 'r') as json_file:
                return json.load(json_file)
        except (FileNotFoundError, json.JSONDecodeError) as e:
            print(f"Error loading JSON configuration: {e}")
            return {}

    def _load_env_config(self):
        return {key: os.environ[key] for key in os.environ}

    def get(self, key, default=None):
        # Precedence: Environment > JSON File > Defaults > Supplied Default
        return self.env_config.get(
            key, 
            self.json_config.get(
                key, 
                self.default_config.get(key, default)
            )
        )

    def set(self, key, value):
        self.env_config[key] = value

    def __getitem__(self, key):
        return self.get(key)

    def __setitem__(self, key, value):
        self.set(key, value)

# Example usage
if __name__ == "__main__":
    default_settings = {
        "api_url": "https://default.api.com",
        "timeout": 30,
        "debug": False
    }

    config_manager = ConfigurationManager(
        default_config=default_settings,
        json_file_path=Path("config.json")
    )

    print(config_manager.get("api_url"))
    print(config_manager.get("timeout"))
    print(config_manager.get("debug"))
