import os
import json
from pathlib import Path

class ConfigurationManager:
    def __init__(self, default_config=None, json_file_path=None):
        self.default_config = default_config or {}
        self.json_file_path = json_file_path
        self.config = self.load_config()

    def load_config(self):
        config = self.default_config.copy()

        # Load JSON file settings if the path is provided
        if self.json_file_path:
            config.update(self.load_json_file(self.json_file_path))

        # Override with environment variables
        config.update(self.load_environment_variables(config.keys()))

        return config

    def load_json_file(self, file_path):
        config_from_file = {}
        try:
            path = Path(file_path)
            if path.is_file():
                with open(path, 'r') as f:
                    config_from_file = json.load(f)
        except json.JSONDecodeError as e:
            print(f"Error decoding JSON from {file_path}: {e}")
        except IOError as e:
            print(f"Error reading file {file_path}: {e}")

        return config_from_file

    def load_environment_variables(self, keys):
        env_config = {}
        for key in keys:
            if key in os.environ:
                env_config[key] = os.environ[key]

        return env_config

    def get(self, key, default=None):
        return self.config.get(key, default)

    def set(self, key, value):
        self.config[key] = value

# Example usage:
