import os
import json
from typing import Any, Dict

class ConfigurationManager:
    def __init__(self, default_config: Dict[str, Any], json_file_path: str = None):
        self.default_config = default_config
        self.json_file_path = json_file_path
        self.config = self.load_config()

    def load_config(self) -> Dict[str, Any]:
        config = self.default_config.copy()

        # Load from JSON file if provided
        if self.json_file_path:
            config.update(self.load_json_config())

        # Load from environment variables
        config.update(self.load_env_config())

        return config

    def load_json_config(self) -> Dict[str, Any]:
        if not os.path.isfile(self.json_file_path):
            return {}
        with open(self.json_file_path, 'r') as json_file:
            return json.load(json_file)

    def load_env_config(self) -> Dict[str, Any]:
        env_config = {}
        for key in self.default_config.keys():
            env_value = os.getenv(key)
            if env_value is not None:
                env_config[key] = self.parse_value(env_value)
        return env_config

    @staticmethod
    def parse_value(value: str) -> Any:
        # Attempt to parse the value to its appropriate type
        if value.lower() in ['true', 'false']:
            return value.lower() == 'true'
        try:
            return int(value)
        except ValueError:
            pass
        try:
            return float(value)
        except ValueError:
            pass
        return value  # Return as string if no other type matches

    def get(self, key: str) -> Any:
        return self.config.get(key)

# Example usage
if __name__ == "__main__":
    default_settings = {
        "APP_PORT": 8000,
        "DEBUG": False,
        "DATABASE_URL": "sqlite:///:memory:"
    }

    config_manager = ConfigurationManager(default_config=default_settings, json_file_path='config.json')

    print(config_manager.get("APP_PORT"))
    print(config_manager.get("DEBUG"))
    print(config_manager.get("DATABASE_URL"))
