import os
import json
from typing import Any, Dict

class ConfigurationManager:
    def __init__(self, json_file_path: str, defaults: Dict[str, Any]):
        self.json_file_path = json_file_path
        self.defaults = defaults
        self.config = self.load_configuration()

    def load_configuration(self) -> Dict[str, Any]:
        config = self.defaults.copy()

        # Load from JSON file
        if os.path.isfile(self.json_file_path):
            with open(self.json_file_path, 'r') as json_file:
                file_config = json.load(json_file)
                config.update(file_config)

        # Load from environment variables
        for key in config.keys():
            env_value = os.getenv(key)
            if env_value is not None:
                config[key] = self.parse_value(env_value)

        return config

    @staticmethod
    def parse_value(value: str) -> Any:
        """Parse string values to their appropriate types."""
        if value.lower() in ['true', 'false']:
            return value.lower() == 'true'
        try:
            return int(value)
        except ValueError:
            try:
                return float(value)
            except ValueError:
                return value  # Return as string if parsing fails

    def get(self, key: str) -> Any:
        return self.config.get(key)

