    def __init__(self, default_config: Dict[str, Any], json_file_path: str = None):
        self.default_config = default_config
        self.json_config = self.load_json_config(json_file_path) if json_file_path else {}
        self.env_config = self.load_env_config()
        self.final_config = self.merge_configs()

