import json


class ConfigManager:
    def __init__(self, defaults=None, json_path=None, env_prefix=""):
        """
        Initializes the configuration manager.

        Parameters:
            defaults (dict): A dictionary of default settings.
            json_path (str): Path to a JSON configuration file.
            env_prefix (str): A prefix that environment variables must start with
                              to be considered. They will be added without the prefix.
        """
        # Start with defaults (lowest precedence).
        self.config = defaults.copy() if defaults else {}

        # Load JSON configuration if provided (overrides defaults).
        if json_path:
            self._load_from_json(json_path)

        # Load environment variables (highest precedence).
        self._load_from_env(env_prefix)

    def _load_from_json(self, json_path):
        """Loads configuration from a JSON file and merges it into current config."""
        try:
            with open(json_path, "r") as f:
                json_config = json.load(f)
            self._deep_update(self.config, json_config)
        except Exception as error:
            print(f"Error loading JSON configuration from {json_path}: {error}")

    def _load_from_env(self, env_prefix):
        """
        Loads environment variables into the configuration.
        If env_prefix is provided, only environment variables starting with it will be loaded.
        The prefix is stripped off when stored in the configuration.
        """
        for key, value in os.environ.items():
            if env_prefix:
                if not key.startswith(env_prefix):
                    continue
                config_key = key[len(env_prefix):]
            else:
                config_key = key

            # Cast the string value to a more specific type if possible.
            casted_value = self._cast_value(value)
            self.config[config_key] = casted_value

    def _cast_value(self, value):
        """
        Attempts to cast the string value to an int, float, or bool.
        Fall back to the original string if no conversion is possible.
        """
        v = value.strip()
        # Handle booleans.
        if v.lower() == "true":
            return True
        elif v.lower() == "false":
            return False

        # Try integer conversion.
        try:
            return int(v)
        except ValueError:
            pass

        # Try float conversion.
        try:
            return float(v)
        except ValueError:
            pass

        return value

    def _deep_update(self, dest, src):
        """
        Recursively updates the destination dict with values from the source dict.
        If a key exists in both and values are dictionaries, merge them.
        Otherwise, the source value overrides the destination.
        """
        for key, value in src.items():
            if (
                key in dest
                and isinstance(dest[key], dict)
                and isinstance(value, dict)
            ):
                self._deep_update(dest[key], value)
            else:
                dest[key] = value

    def get(self, key, default=None):
        """Retrieves a configuration value with an optional default."""
        return self.config.get(key, default)

    def __getitem__(self, key):
        return self.config[key]

    def __str__(self):
        return str(self.config)


