class ConfigManager:
    def __init__(self, defaults, json_file=None, env_prefix=""):
        """
        Initialize the configuration manager.

        Precedence (highest to lowest):
            1. Environment variables
            2. JSON configuration file
            3. Defaults

        Arguments:
            defaults (dict): The default configuration values.
            json_file (str, optional): Path to a JSON file with configuration values.
            env_prefix (str, optional): A prefix for environment variables. For example, if key is "host"
                and prefix is "MYAPP_", then the environment variable looked up will be "MYAPP_HOST". 
                Defaults to "".
        """
        # Start with the defaults in our configuration dictionary.
        self._config = defaults.copy()

        # If a JSON file is provided, update the configuration with its contents.
        if json_file:
            try:
                with open(json_file, "r") as jf:
                    json_config = json.load(jf)
                # Update our config with values from the JSON file; note that they override defaults.
                self._config.update(json_config)
            except FileNotFoundError:
                # Could log or handle the error as needed.
                print(f"Warning: JSON configuration file '{json_file}' not found. Using defaults and environment variables only.")
            except json.JSONDecodeError as e:
                print(f"Error: Failed to parse JSON file '{json_file}': {e}")

        # Finally, override with environment variables.
        # We consider all keys currently in our configuration.
        for key in list(self._config.keys()):
            # Construct the corresponding environment variable name.
            # We convert the key to upper-case and prepend the env_prefix.
            env_key = f"{env_prefix}{key.upper()}"
            env_value = os.getenv(env_key)
            if env_value is not None:
                # Optionally, you may want to cast env_value to the type of defaults[key]
                self._config[key] = self._cast_value(env_value, type(self._config[key]))

    def _cast_value(self, value, target_type):
        """
        Cast the environment variable string value to the target type.
        Supports int, float, bool, and str. For bool, the strings "true" (case-insensitive)
        and "1" are considered True; "false" and "0" are considered False.
        """
        try:
            if target_type == bool:
                val_lower = value.lower()
                if val_lower in ("true", "1", "yes", "on"):
                    return True
                elif val_lower in ("false", "0", "no", "off"):
                    return False
                else:
                    return bool(value)
            elif target_type == int:
                return int(value)
            elif target_type == float:
                return float(value)
            else:
                return value
        except Exception:
            return value

    def get(self, key, default=None):
        """
        Retrieve the configuration value for the given key.
        If the key is not present, return the provided default.
        """
        return self._config.get(key, default)

    def set(self, key, value):
        """
        Set or override a configuration value.
        """
        self._config[key] = value

    def as_dict(self):
        """
        Return a copy of the configuration as a dictionary.
        """
        return self._config.copy()


