import os
import json


class ConfigManager:
    """
    Configuration manager that loads settings from defaults, a JSON file, 
    and environment variables with proper precedence:

      defaults < JSON file < environment variables

    Optional environment variable prefix can be provided; only variables
    whose names start with the prefix will override config keys.
    """

    def __init__(self, defaults: dict, json_file: str = None, env_prefix: str = ""):
        """
        Initialize the configuration manager.

        Parameters:
            defaults (dict): A dictionary of default configuration values.
            json_file (str, optional): Path to a JSON configuration file. Defaults to None.
            env_prefix (str, optional): A prefix filter for environment variables. Only
                environment variables starting with this prefix will be considered.
                Defaults to "" (meaning all environment variables are used).
        """
        self._config = defaults.copy()

        # Load settings from JSON config file (if provided)
        if json_file:
            self._load_from_json(json_file)

        # Override with environment variables
        self._load_from_env(env_prefix)

    def _load_from_json(self, json_file: str):
        try:
            with open(json_file, "r") as f:
                json_config = json.load(f)
            if not isinstance(json_config, dict):
                raise ValueError("JSON configuration should be a dictionary.")
            # Update configuration with JSON values (overrides defaults)
            self._config.update(json_config)
        except Exception as e:
            raise RuntimeError(f"Failed to load JSON config from {json_file}: {e}")

    def _load_from_env(self, env_prefix: str):
        """
        Iterate over environment variables and override configuration keys.
        If an env_prefix is provided, only consider variables that start with it.
        The key in the config will be taken as the env variable name with the prefix removed.
        If no prefix is provided, the entire environment variable dictionary is used to update the config.
        """
        for env_key, env_value in os.environ.items():
            if env_prefix:
                if not env_key.startswith(env_prefix):
                    continue
                key = env_key[len(env_prefix):]
            else:
                key = env_key

            # If the config already contains this key, attempt type conversion based on the default value.
            if key in self._config:
                self._config[key] = self._convert_type(env_value, type(self._config[key]))
            else:
                # Otherwise, store as string
                self._config[key] = env_value

    @staticmethod
    def _convert_type(value: str, target_type):
        """
        Convert the string value from an environment variable to the target type.
        Currently supports: bool, int, float, list (comma-separated), and leaves as string as fallback.
        """
        try:
            if target_type is bool:
                # Convert typical string representations of booleans.
                lower_val = value.lower()
                if lower_val in ("true", "1", "yes", "on"):
                    return True
                elif lower_val in ("false", "0", "no", "off"):
                    return False
                else:
                    raise ValueError(f"Cannot convert {value} to bool.")
            elif target_type is int:
                return int(value)
            elif target_type is float:
                return float(value)
            elif target_type is list:
                # Assume comma separated values for lists.
                return [item.strip() for item in value.split(",")]
            else:
                # Default: return string or let other types handle conversion if possible.
                return value
        except Exception:
            # In case of any conversion error, return the raw string.
            return value

    def get(self, key: str, default=None):
        """
        Retrieve a configuration value.

        Parameters:
            key (str): The configuration key.
            default: Default value if the key is not found.

        Returns:
            The configuration value if present; otherwise the default.
        """
        return self._config.get(key, default)

    def __getitem__(self, key: str):
        return self._config[key]

    def __setitem__(self, key: str, value):
        self._config[key] = value

    def as_dict(self) -> dict:
        """
        Return the entire configuration as a dictionary.
        """
        return self._config.copy()


