        """
        self.defaults = defaults or {}
        # Save the types of keys from defaults for proper type casting later.
        self.default_types = {key: type(value) for key, value in self.defaults.items()}
        self.json_file = json_file
        self.env_prefix = env_prefix
        self.config = {}
