    def load_config(self):
        """
        Loads configuration values from defaults, then updates them from a JSON file (if provided),
        and finally overrides them with any existing environment variables.

        Precedence: environment variables > JSON file > defaults.
        """
        # 1. Start with defaults.
        self.config = self.defaults.copy()

        # 2. Update from JSON file if one is provided.
        if self.json_file:
            try:
                with open(self.json_file, "r") as f:
                    json_config = json.load(f)
                self._deep_update(self.config, json_config)
            except Exception as e:
                print(f"Error loading JSON configuration from '{self.json_file}': {e}")

        # 3. Override with environment variables.
        # We'll update all keys already present in self.config.  For keys that were not in defaults,
        # type conversion is not performed and the environment variable is used as a string.
        keys = list(self.config.keys())
        for key in keys:
            env_key = f"{self.env_prefix}{key.upper()}"
