                config = json.load(f)
                self.logger.info(f"Loaded configuration from {self.config_file}")
                return {self._normalize_key(k): v for k, v in config.items()}
        except (json.JSONDecodeError, IOError) as e:
            self.logger.error(f"Failed to load configuration file {self.config_file}: {e}")
            return {}

    def _load_environment_variables(self) -> Dict[str, Any]:
        """Load configuration from environment variables."""
        env_config = {}
        prefix_len = len(self.env_prefix)

        for key, value in os.environ.items():
            if self.env_prefix and not key.startswith(self.env_prefix):
