    def _load_from_environment(self) -> None:
        """Load configuration from environment variables."""
        for key, value in os.environ.items():
            # Convert environment variable to nested dictionary key
            config_key = key.lower()
            self._set_nested_value(config_key, self._convert_env_value(value))

    def _merge_config(self, source_config: Dict[str, Any]) -> None:
        """Merge configuration from source into main config."""
        for key, value in source_config.items():
            if isinstance(value, dict) and key in self._config and isinstance(self._config[key], dict):
                self._config[key].update(value)
            else:
