import os
import json
from typing import Any, Dict, Optional, Union
from pathlib import Path


class ConfigurationManager:
    """
    Configuration manager that loads settings from multiple sources with precedence:
    1. Environment variables (highest priority)
    2. JSON configuration files
    3. Default values (lowest priority)
    """

    def __init__(self, config_file: Optional[Union[str, Path]] = None, env_prefix: str = ""):
        """
        Initialize the configuration manager.

        Args:
            config_file: Path to JSON configuration file
            env_prefix: Prefix for environment variables (e.g., "MYAPP_")
        """
        self.config_file = Path(config_file) if config_file else None
        self.env_prefix = env_prefix.upper()
        self._config: Dict[str, Any] = {}
        self._defaults: Dict[str, Any] = {}

        self._load_configuration()

    def set_defaults(self, defaults: Dict[str, Any]) -> None:
        """Set default configuration values."""
        self._defaults = defaults.copy()
        self._load_configuration()

    def _load_configuration(self) -> None:
        """Load configuration from all sources with proper precedence."""
        # Start with defaults
        self._config = self._defaults.copy()

        # Override with JSON file settings
        if self.config_file and self.config_file.exists():
            try:
                with open(self.config_file, 'r', encoding='utf-8') as f:
                    file_config = json.load(f)
                    self._merge_config(self._config, file_config)
            except (json.JSONDecodeError, IOError) as e:
                raise ConfigurationError(f"Failed to load config file {self.config_file}: {e}")

        # Override with environment variables (highest precedence)
        self._load_from_environment()

    def _load_from_environment(self) -> None:
        """Load configuration from environment variables."""
        for key, value in os.environ.items():
            if self.env_prefix and key.startswith(self.env_prefix):
                # Remove prefix and convert to lowercase
                config_key = key[len(self.env_prefix):].lower()
                if config_key.startswith('_'):
                    config_key = config_key[1:]
            elif not self.env_prefix:
                config_key = key.lower()
            else:
                continue

            # Convert nested keys (e.g., DATABASE_HOST -> database.host)
            nested_keys = config_key.split('_')
            self._set_nested_value(self._config, nested_keys, self._parse_env_value(value))

    def _parse_env_value(self, value: str) -> Any:
        """Parse environment variable value to appropriate type."""
        # Try to parse as JSON first (for complex types)
        try:
            return json.loads(value)
        except json.JSONDecodeError:
            pass

        # Handle boolean values
        if value.lower() in ('true', 'false'):
            return value.lower() == 'true'

        # Handle numeric values
        try:
            if '.' in value:
                return float(value)
            return int(value)
        except ValueError:
            pass

        # Return as string
        return value

    def _set_nested_value(self, config: Dict[str, Any], keys: list, value: Any) -> None:
        """Set a nested configuration value using a list of keys."""
        current = config
        for key in keys[:-1]:
            if key not in current:
                current[key] = {}
            elif not isinstance(current[key], dict):
                current[key] = {}
            current = current[key]

        current[keys[-1]] = value

    def _merge_config(self, target: Dict[str, Any], source: Dict[str, Any]) -> None:
        """Recursively merge source configuration into target."""
        for key, value in source.items():
            if key in target and isinstance(target[key], dict) and isinstance(value, dict):
                self._merge_config(target[key], value)
            else:
                target[key] = value

    def get(self, key: str, default: Any = None) -> Any:
        """
        Get a configuration value using dot notation.

        Args:
            key: Configuration key (supports dot notation, e.g., 'database.host')
            default: Default value if key is not found

        Returns:
            Configuration value or default
        """
        keys = key.split('.')
        current = self._config

        try:
            for k in keys:
                current = current[k]
            return current
        except (KeyError, TypeError):
            return default

    def get_int(self, key: str, default: int = 0) -> int:
        """Get configuration value as integer."""
        value = self.get(key, default)
        try:
            return int(value)
        except (ValueError, TypeError):
            return default

    def get_float(self, key: str, default: float = 0.0) -> float:
        """Get configuration value as float."""
        value = self.get(key, default)
        try:
            return float(value)
        except (ValueError, TypeError):
            return default

    def get_bool(self, key: str, default: bool = False) -> bool:
        """Get configuration value as boolean."""
        value = self.get(key, default)
        if isinstance(value, bool):
            return value
        if isinstance(value, str):
            return value.lower() in ('true', '1', 'yes', 'on')
        return bool(value)

    def get_list(self, key: str, default: list = None) -> list:
        """Get configuration value as list."""
        if default is None:
            default = []
        value = self.get(key, default)
        if isinstance(value, list):
            return value
        if isinstance(value, str):
            # Try to parse as JSON array
            try:
                parsed = json.loads(value)
                return parsed if isinstance(parsed, list) else default
            except json.JSONDecodeError:
                # Split by comma as fallback
                return [item.strip() for item in value.split(',') if item.strip()]
        return default

    def set(self, key: str, value: Any) -> None:
        """
        Set a configuration value using dot notation.

        Args:
            key: Configuration key (supports dot notation)
            value: Value to set
        """
        keys = key.split('.')
        self._set_nested_value(self._config, keys, value)

    def has(self, key: str) -> bool:
        """Check if a configuration key exists."""
        return self.get(key, object()) is not object()

    def to_dict(self) -> Dict[str, Any]:
        """Return the entire configuration as a dictionary."""
        return self._config.copy()

    def reload(self) -> None:
        """Reload configuration from all sources."""
        self._load_configuration()

    def save_to_file(self, file_path: Union[str, Path]) -> None:
        """Save current configuration to a JSON file."""
        file_path = Path(file_path)
        try:
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(self._config, f, indent=2, ensure_ascii=False)
        except IOError as e:
            raise ConfigurationError(f"Failed to save config to {file_path}: {e}")


