import os
import json
from typing import Any, Dict, Optional, Union
from pathlib import Path


class ConfigurationManager:
    """
    Configuration manager that loads settings from multiple sources with precedence:
    1. Environment variables (highest priority)
    2. JSON configuration files
    3. Default values (lowest priority)
    """

    def __init__(self, config_file: Optional[Union[str, Path]] = None, 
                 env_prefix: str = "", defaults: Optional[Dict[str, Any]] = None):
        """
        Initialize the configuration manager.

        Args:
            config_file: Path to JSON configuration file
            env_prefix: Prefix for environment variables (e.g., 'APP_' for APP_DATABASE_URL)
            defaults: Dictionary of default configuration values
        """
        self.config_file = Path(config_file) if config_file else None
        self.env_prefix = env_prefix.upper()
        self.defaults = defaults or {}
        self._config = {}
        self._load_configuration()

    def _load_configuration(self) -> None:
        """Load configuration from all sources in precedence order."""
        # Start with defaults
        self._config = self.defaults.copy()

        # Load from JSON file if provided
        if self.config_file:
            self._load_from_json()

        # Override with environment variables
        self._load_from_environment()

    def _load_from_json(self) -> None:
        """Load configuration from JSON file."""
        if not self.config_file.exists():
            return

        try:
            with open(self.config_file, 'r', encoding='utf-8') as file:
                json_config = json.load(file)
                self._merge_config(json_config)
        except (json.JSONDecodeError, IOError) as e:
            raise ConfigurationError(f"Failed to load JSON config from {self.config_file}: {e}")

    def _load_from_environment(self) -> None:
        """Load configuration from environment variables."""
        for key, value in os.environ.items():
            if self.env_prefix and not key.startswith(self.env_prefix):
                continue

            # Remove prefix and convert to lowercase
            config_key = key[len(self.env_prefix):].lower() if self.env_prefix else key.lower()

            # Convert nested keys (e.g., DATABASE__HOST -> database.host)
            config_key = config_key.replace('__', '.')

            # Parse value with type inference
            parsed_value = self._parse_env_value(value)
            self._set_nested_value(config_key, parsed_value)

    def _parse_env_value(self, value: str) -> Any:
        """Parse environment variable value with basic type inference."""
        if not value:
            return ""

        # Boolean values
        if value.lower() in ('true', 'false'):
            return value.lower() == 'true'

        # Numeric values
        try:
            if '.' in value:
                return float(value)
            return int(value)
        except ValueError:
            pass

        # JSON values
        if value.startswith(('{', '[', '"')):
            try:
                return json.loads(value)
            except json.JSONDecodeError:
                pass

        return value

    def _merge_config(self, source_config: Dict[str, Any]) -> None:
        """Merge source configuration into main config."""
        def merge_dict(target: Dict[str, Any], source: Dict[str, Any]) -> None:
            for key, value in source.items():
                if isinstance(value, dict) and key in target and isinstance(target[key], dict):
                    merge_dict(target[key], value)
                else:
                    target[key] = value

        merge_dict(self._config, source_config)

    def _set_nested_value(self, key_path: str, value: Any) -> None:
        """Set a nested configuration value using dot notation."""
        keys = key_path.split('.')
        current = self._config

        for key in keys[:-1]:
            if key not in current or not isinstance(current[key], dict):
                current[key] = {}
            current = current[key]

        current[keys[-1]] = value

    def _get_nested_value(self, key_path: str) -> Any:
        """Get a nested configuration value using dot notation."""
        keys = key_path.split('.')
        current = self._config

        for key in keys:
            if not isinstance(current, dict) or key not in current:
                raise KeyError(f"Configuration key '{key_path}' not found")
            current = current[key]

        return current

    def get(self, key: str, default: Any = None) -> Any:
        """
        Get a configuration value.

        Args:
            key: Configuration key (supports dot notation for nested values)
            default: Default value if key is not found

        Returns:
            Configuration value or default
        """
        try:
            return self._get_nested_value(key)
        except KeyError:
            return default

    def get_required(self, key: str) -> Any:
        """
        Get a required configuration value.

        Args:
            key: Configuration key

        Returns:
            Configuration value

        Raises:
            ConfigurationError: If the required key is not found
        """
        try:
            return self._get_nested_value(key)
        except KeyError:
            raise ConfigurationError(f"Required configuration key '{key}' is missing")

    def get_int(self, key: str, default: Optional[int] = None) -> int:
        """Get an integer configuration value."""
        value = self.get(key, default)
        if value is None:
            raise ConfigurationError(f"Configuration key '{key}' is required")
        try:
            return int(value)
        except (ValueError, TypeError):
            raise ConfigurationError(f"Configuration key '{key}' must be an integer")

    def get_bool(self, key: str, default: Optional[bool] = None) -> bool:
        """Get a boolean configuration value."""
        value = self.get(key, default)
        if value is None:
            raise ConfigurationError(f"Configuration key '{key}' is required")
        if isinstance(value, bool):
            return value
        if isinstance(value, str):
            return value.lower() in ('true', '1', 'yes', 'on')
        return bool(value)

    def get_float(self, key: str, default: Optional[float] = None) -> float:
        """Get a float configuration value."""
        value = self.get(key, default)
        if value is None:
            raise ConfigurationError(f"Configuration key '{key}' is required")
        try:
            return float(value)
        except (ValueError, TypeError):
            raise ConfigurationError(f"Configuration key '{key}' must be a float")

    def get_list(self, key: str, default: Optional[list] = None) -> list:
        """Get a list configuration value."""
        value = self.get(key, default or [])
        if isinstance(value, list):
            return value
        if isinstance(value, str):
            # Handle comma-separated values
            return [item.strip() for item in value.split(',') if item.strip()]
        raise ConfigurationError(f"Configuration key '{key}' must be a list")

    def has(self, key: str) -> bool:
        """Check if a configuration key exists."""
        try:
            self._get_nested_value(key)
            return True
        except KeyError:
            return False

    def reload(self) -> None:
        """Reload configuration from all sources."""
        self._load_configuration()

    def to_dict(self) -> Dict[str, Any]:
        """Return the complete configuration as a dictionary."""
        return self._config.copy()

    def __getitem__(self, key: str) -> Any:
        """Allow dictionary-style access."""
        return
